namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    #region CreateOrder — Happy Path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsCustomerId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order = _service.CreateOrder("cust-42", items);

        // Assert
        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_GeneratesNonEmptyId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Alpha", Price = 1.00m, Quantity = 1 },
            new() { ProductName = "Beta", Price = 2.00m, Quantity = 3 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    [DataRow(10.00, 3, 30.00, DisplayName = "Single item quantity 3")]
    [DataRow(7.50, 1, 7.50, DisplayName = "Single item quantity 1")]
    [DataRow(0.01, 100, 1.00, DisplayName = "Penny item quantity 100")]
    public void CreateOrder_SingleItem_CalculatesTotalCorrectly(
        double price, int quantity, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion

    #region CreateOrder — Validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", items));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
        Assert.AreEqual(created.Total, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        // Act
        var results = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        // Act
        var results = _service.GetOrdersByCustomer("unknown-customer");

        // Assert
        Assert.IsNotNull(results);
        Assert.IsEmpty(results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingCustomerOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        // Act
        var results = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.ContainsSingle(results);
        Assert.AreEqual("cust-A", results[0].CustomerId);
    }

    #endregion

    #region Integration — CreateOrder then retrieve

    [TestMethod]
    public void CreateOrder_ThenGetOrder_ReturnsSameOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Deluxe Widget", Price = 99.99m, Quantity = 2 },
        };

        // Act
        var created = _service.CreateOrder("cust-1", items);
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void CreateOrder_MultipleOrders_EachGetsUniqueId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion
}

